from minitemplate import Template

class Obj:
    def __init__(self):
        self.name = 'attr-value'

t = Template('{{ obj.name }} / {{ d.key }}')
print(t.render(obj=Obj(), d={'key': 'dict-value'}))

from minitemplate import Template, UndefinedError
t = Template('{{ missing }}')
try:
    t.render()
    print('no-error')
except UndefinedError:
    print('undefined')
except Exception:
    print('other-error')
print(issubclass(UndefinedError, NameError))
